async function loadBookings() {
  try {
    const rows = await sbFetch("/bookings?order=created_at.desc");
    return rows.map(fromRow);
  } catch (e) {
    console.error("loadBookings error:", e);
    return [];
  }
}

async function insertBooking(booking) {
  try {
    await sbFetch("/bookings", {
      method: "POST",
      body: JSON.stringify(toRow(booking)),
      prefer: "return=minimal",
    });
    return true;
  } catch (e) {
    console.error("insertBooking error:", e);
    return false;
  }
}

async function patchBooking(id, updates) {
  const row = {};
  if (updates.status !== undefined) row.status = updates.status;
  if (updates.cancellationFee !== undefined) row.cancellation_fee = updates.cancellationFee;
  if (updates.paymentStatus !== undefined) row.payment_status = updates.paymentStatus;
  try {
    await sbFetch(`/bookings?id=eq.${id}`, {
      method: "PATCH",
      body: JSON.stringify(row),
      prefer: "return=minimal",
    });
    return true;
  } catch (e) {
    console.error("patchBooking error:", e);
    return false;
  }
}

/* ============================== HELPERS ============================== */
function uid() {
  return Date.now().toString(36) + Math.random().toString(36).slice(2, 7);
}
function normalizePhone(p) { return (p || "").replace(/\D/g, ""); }
function isReturningCustomer(bookings, email, phone) {
  const e = (email || "").trim().toLowerCase();
  const p = normalizePhone(phone);
  return bookings.some(
    (b) => (b.email || "").toLowerCase() === e || (p && normalizePhone(b.phone) === p)
  );
}
function priceFor(tier, newClient) {
  if (!tier || tier.price == null) return { base: null, discount: 0, final: null };
  const base = tier.price;
  const discount = newClient ? Math.round(base * NEW_CLIENT_DISCOUNT) : 0;
  return { base, discount, final: base - discount };
}
function hoursUntil(dateStr, timeStr) {
  const t = parseTimeToMinutes(timeStr);
  const dt = new Date(dateStr + "T00:00:00");
  dt.setMinutes(t);
  return (dt.getTime() - Date.now()) / 36e5;
}
function parseTimeToMinutes(label) {
  const m = label.match(/(\d+):(\d+)\s*(AM|PM)/i);
  if (!m) return 9 * 60;
  let h = parseInt(m[1], 10);
  const min = parseInt(m[2], 10);
  if (/pm/i.test(m[3]) && h !== 12) h += 12;
  if (/am/i.test(m[3]) && h === 12) h = 0;
  return h * 60 + min;
}
function formatDateLabel(dateStr) {
  if (!dateStr) return "";
  const d = new Date(dateStr + "T00:00:00");
  return d.toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric", year: "numeric" });
}
function money(n) {
  if (n == null) return "—";
  return `$${n.toLocaleString()}`;
}
function todayStr() {
  const d = new Date();
  return d.toISOString().slice(0, 10);
}
function downloadCSV(filename, rows) {
  const csv = rows.map((r) => r.map((c) => `"${String(c ?? "").replace(/"/g, '""')}"`).join(",")).join("\n");
  const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

